from pybricks.hubs import InventorHub
from pybricks.parameters import Button, Direction, Port
from pybricks.pupdevices import Motor
from pybricks.robotics import DriveBase

from line_sensor_pybricks import LineSensorUR

# Set up.
ls = LineSensorUR('B')
inventor_hub = InventorHub()
left_motor = Motor(Port.F, Direction.COUNTERCLOCKWISE)
right_motor = Motor(Port.E, Direction.CLOCKWISE)
drive_base = DriveBase(left_motor, right_motor, 89, 114)


# The main program starts here.
# upload line_sensor_pybricks.py into your pybricks code environment. Get it here:
# https://github.com/AntonsMindstorms/lms-line-sensor/blob/main/micropython/line_sensor_pybricks.py
print(ls.mode_calibrated())
while True:
    if any(inventor_hub.buttons.pressed()):
        ls.calibrate()
    drive_base.drive(100, ls.position())
